        // Phase 1: find candidates
        for (int i = 0; i < n; ++i) {
            if (a[i] == el1) cnt1++;
            else if (a[i] == el2) cnt2++;
            else if (cnt1 == 0) { el1 = a[i]; cnt1 = 1; }
            else if (cnt2 == 0) { el2 = a[i]; cnt2 = 1; }
            else { cnt1--; cnt2--; }
        }
        // Phase 2: validate
        cnt1 = cnt2 = 0;
        for (int i = 0; i < n; ++i) {
            if (a[i] == el1) cnt1++;
            else if (a[i] == el2) cnt2++;
        }
        int printed = 0;
        int limit = n / 3;
        if (cnt1 > limit) { printf("%lld", el1); printed = 1; }
        if (cnt2 > limit) {
