                if (el2 < el1) {
                    // need to output in increasing order, swap order of printing
                    printf(" %lld", el1);
                    printf(" %lld", el2);
                } else {
                    printf(" %lld", el2);
                }
            } else {
                printf("%lld", el2);
                printed = 1;
            }
        }
        if (!printed) {
            // print nothing, just a newline
        }
        printf("\n");
        free(a);
    }
    return 0;
}

