        // candidate selection
        for (long long x : a) {
            if (x == el1) ++cnt1;
            else if (x == el2) ++cnt2;
            else if (cnt1 == 0) { el1 = x; cnt1 = 1; }
            else if (cnt2 == 0) { el2 = x; cnt2 = 1; }
            else { --cnt1; --cnt2; }
        }
        // validation
        cnt1 = cnt2 = 0;
        for (long long x : a) {
            if (x == el1) ++cnt1;
            else if (x == el2) ++cnt2;
        }
        vector<long long> ans;
        int limit = n / 3;
        if (cnt1 > limit) ans.push_back(el1);
        if (cnt2 > limit) ans.push_back(el2);
        sort(ans.begin(), ans.end());
        for (size_t i = 0; i < ans.size(); ++i) {
            if (i) cout << ' ';
            cout << ans[i];
        }
        cout << '\n';
    }
    return 0;
