import sys

def find_superstar(a, n):
    el1 = el2 = None
    cnt1 = cnt2 = 0
    # candidate selection
    for x in a:
        if el1 == x:
            cnt1 += 1
        elif el2 == x:
            cnt2 += 1
        elif cnt1 == 0:
            el1 = x
            cnt1 = 1
        elif cnt2 == 0:
            el2 = x
            cnt2 = 1
        else:
            cnt1 -= 1
            cnt2 -= 1
    # validation
    cnt1 = cnt2 = 0
    for x in a:
        if x == el1:
            cnt1 += 1
        elif x == el2:
            cnt2 += 1
    ans = []
    limit = n // 3
    if cnt1 > limit:
        ans.append(el1)
    if cnt2 > limit:
        ans.append(el2)
    ans.sort()
    return ans

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        n = int(next(it))
        a = [int(next(it)) for _ in range(n)]
        res = find_superstar(a, n)
        out_lines.append(' '.join(map(str, res)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

